/// Static capability flags for a provider.
///
/// Each flag indicates whether the provider's models *generally* support that
/// feature.  For providers that aggregate many underlying models (e.g. Bedrock,
/// OpenRouter, vLLM) the flags reflect the superset of available model
/// capabilities — a flag being `true` means at least one model supports the
/// feature, not every model.
///
/// All flags default to `false` so that newly added providers are safe.
///
/// Access via the crate-level [`capabilities`] function:
///
/// ```rust
/// use liter_llm::capabilities;
///
/// let caps = capabilities("openai");
/// assert!(caps.function_calling);
/// assert!(caps.vision);
///
/// // Unknown providers return a default-all-false reference.
/// let unknown = capabilities("my-private-model");
/// assert!(!unknown.function_calling);
/// ```
public struct ProviderCapabilities: Codable, Sendable, Hashable {
    /// The provider accepts image input in chat messages.
    public let vision: Bool
    /// The provider supports extended-thinking / reasoning tokens.
    public let reasoning: Bool
    /// The provider supports JSON-mode or `response_format` structured output.
    public let structuredOutput: Bool
    /// The provider supports tool / function calling.
    public let functionCalling: Bool
    /// The provider accepts audio as input.
    public let audioIn: Bool
    /// The provider can generate audio / TTS output.
    public let audioOut: Bool
    /// The provider accepts video as input.
    public let videoIn: Bool
    public init(vision: Bool, reasoning: Bool, structuredOutput: Bool, functionCalling: Bool, audioIn: Bool, audioOut: Bool, videoIn: Bool) {
        self.vision = vision
        self.reasoning = reasoning
        self.structuredOutput = structuredOutput
        self.functionCalling = functionCalling
        self.audioIn = audioIn
        self.audioOut = audioOut
        self.videoIn = videoIn
    }
    private enum CodingKeys: String, CodingKey {
        case vision = "vision"
        case reasoning = "reasoning"
        case structuredOutput = "structured_output"
        case functionCalling = "function_calling"
        case audioIn = "audio_in"
        case audioOut = "audio_out"
        case videoIn = "video_in"
    }
    public init(from decoder: any Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        self.vision = try container.decodeIfPresent(Bool.self, forKey: .vision) ?? false
        self.reasoning = try container.decodeIfPresent(Bool.self, forKey: .reasoning) ?? false
        self.structuredOutput = try container.decodeIfPresent(Bool.self, forKey: .structuredOutput) ?? false
        self.functionCalling = try container.decodeIfPresent(Bool.self, forKey: .functionCalling) ?? false
        self.audioIn = try container.decodeIfPresent(Bool.self, forKey: .audioIn) ?? false
        self.audioOut = try container.decodeIfPresent(Bool.self, forKey: .audioOut) ?? false
        self.videoIn = try container.decodeIfPresent(Bool.self, forKey: .videoIn) ?? false
    }
}

