// MARK: - Free-function Forwarders
// Re-export every public free function on the source Rust crate as a
// top-level `public func` on the host module so consumers do not need to
// `import RustBridge` directly. Forwarders take Swift-native parameter
// types and convert to the swift-bridge runtime types internally.

/// Create a new LLM client with simple scalar configuration.
///
/// This is the primary binding entry-point. All parameters except `api_key`
/// are optional — omitting them uses the same defaults as
/// [`ClientConfigBuilder`].
///
/// # Errors
///
/// Returns [`LiterLlmError`] if the underlying HTTP client cannot be
/// constructed, or if the resolved provider configuration is invalid.
public func createClient(apiKey: String, baseUrl: String? = nil, timeoutSecs: UInt64? = nil, maxRetries: UInt32? = nil, modelHint: String? = nil) throws -> DefaultClient {
        let _rb_apiKey = RustString(apiKey)
        let _rb_baseUrl = baseUrl.map { RustString($0) }
        let _rb_modelHint = modelHint.map { RustString($0) }
    let _rb = try RustBridge.createClient(_rb_apiKey, _rb_baseUrl, timeoutSecs, maxRetries, _rb_modelHint)
    return DefaultClient(_rb)
}
/// Create a new LLM client from a JSON string.
///
/// The JSON object accepts the same fields as `liter-llm.toml` (snake_case).
///
/// # Errors
///
/// Returns [`LiterLlmError::BadRequest`] if `json` is not valid JSON or
/// contains unknown fields.
public func createClientFromJson(json: String) throws -> DefaultClient {
        let _rb_json = RustString(json)
    let _rb = try RustBridge.createClientFromJson(_rb_json)
    return DefaultClient(_rb)
}
/// Encode bytes as a base64 data URL: `data:<mime>;base64,<b64>`.
///
/// `mime` defaults to [`IMAGE_PNG`] when `None`.
///
/// # Example
///
/// ```
/// use liter_llm::image::{encode_data_url, IMAGE_PNG, IMAGE_JPEG};
///
/// let url = encode_data_url(b"\x89PNG", Some(IMAGE_PNG));
/// assert!(url.starts_with("data:image/png;base64,"));
///
/// let url_default = encode_data_url(b"\x89PNG", None);
/// assert!(url_default.starts_with("data:image/png;base64,"));
///
/// let jpeg_url = encode_data_url(b"\xff\xd8\xff", Some(IMAGE_JPEG));
/// assert!(jpeg_url.starts_with("data:image/jpeg;base64,"));
/// ```
public func encodeDataUrl(bytes: [UInt8], mime: String? = nil) -> String {
        let _rb_bytes: RustVec<UInt8> = { let v = RustVec<UInt8>(); for b in bytes { v.push(value: b) }; return v }()
        let _rb_mime = mime.map { RustString($0) }
    return RustBridge.encodeDataUrl(_rb_bytes, _rb_mime).toString()
}
/// Decode a base64 data URL into [`DecodedDataUrl`].
///
/// Returns `None` for:
/// - Non-data URLs (strings that do not start with `"data:"`).
/// - Malformed prefixes (missing `";base64,"` marker).
/// - Invalid base64 payloads.
///
/// The returned MIME string is extracted verbatim from the URL prefix —
/// it is not validated or normalised.
///
/// # Example
///
/// ```
/// use liter_llm::image::{encode_data_url, decode_data_url, IMAGE_PNG};
///
/// let url = encode_data_url(b"hello", Some(IMAGE_PNG));
/// let decoded = decode_data_url(&url).expect("valid data URL");
/// assert_eq!(decoded.mime, IMAGE_PNG);
/// assert_eq!(decoded.data, b"hello");
///
/// // Non-data URLs return None.
/// assert!(decode_data_url("https://example.com/img.png").is_none());
///
/// // Missing ;base64, marker returns None.
/// assert!(decode_data_url("data:image/png,plaintext").is_none());
/// ```
public func decodeDataUrl(url: String) -> DecodedDataUrl? {
        let _rb_url = RustString(url)
    return RustBridge.decodeDataUrl(_rb_url)
}
